function escapeHtml(value=''){
  return String(value)
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;')
    .replace(/'/g,'&#39;');
}

function computeScore(hero){
  const dragonBonus = hero.killedDragon ? 200 : 0;
  return hero.gold + (hero.items.length * 50) + (hero.body * 10) + dragonBonus;
}

function getScorePayload(hero){
  return {
    firstName: '',
    lastName: '',
    heroName: hero.name,
    heroClass: hero.cls,
    gold: hero.gold,
    itemsCount: hero.items.length,
    remainingBody: hero.body,
    score: computeScore(hero),
    killedDragon: !!hero.killedDragon
  };
}

async function fetchHighscores(){
  const loading=document.getElementById('highscores-loading');
  const empty=document.getElementById('highscores-empty');
  const list=document.getElementById('highscores-list');
  if(!loading||!empty||!list)return;
  loading.hidden=false;
  empty.hidden=true;
  list.innerHTML='';
  try{
    const res=await fetch('/api/highscores');
    if(!res.ok) throw new Error('Impossible de charger les scores');
    const data=await res.json();
    highscoresCache=Array.isArray(data)?data:[];
    renderHighscores();
  }catch(err){
    loading.hidden=true;
    empty.hidden=false;
    empty.textContent='Impossible de charger le classement.';
    console.error(err);
  }
}

function renderHighscores(){
  const loading=document.getElementById('highscores-loading');
  const empty=document.getElementById('highscores-empty');
  const list=document.getElementById('highscores-list');
  if(!loading||!empty||!list)return;
  loading.hidden=true;
  list.innerHTML='';
  if(!highscoresCache.length){
    empty.hidden=false;
    empty.textContent='Aucun score enregistré pour le moment.';
    return;
  }
  empty.hidden=true;
  highscoresCache.slice(0,10).forEach((entry,index)=>{
    const row=document.createElement('div');
    row.className='highscore-row';
    const fullname=[entry.first_name, entry.last_name].filter(Boolean).join(' ').trim() || 'Aventurier inconnu';
    const dragonBadge=entry.killed_dragon ? ' · 🐉 Dragon' : '';
    row.innerHTML=
      `<div class="highscore-rank">#${index+1}</div>
       <div>
         <div class="highscore-name">${escapeHtml(fullname)}</div>
         <div class="highscore-meta">${escapeHtml(entry.hero_name || 'Héros')} · ${escapeHtml(entry.hero_class || 'Classe inconnue')} · ${entry.gold || 0}💰 · ${entry.items_count || 0} objet(s) · ${entry.remaining_body || 0} PV${dragonBadge}</div>
       </div>
       <div class="highscore-score">${entry.score || 0}</div>`;
    list.appendChild(row);
  });
}

function openScoreSubmission(hero){
  pendingScorePayload=getScorePayload(hero);
  showModal(
    '🏆 Enregistrer ton score',
    `<div class="score-form">
       <input id="score-firstname" type="text" maxlength="40" placeholder="Prénom">
       <input id="score-lastname" type="text" maxlength="40" placeholder="Nom">
     </div>
     <div class="score-save-hint">Score calculé : ${pendingScorePayload.score} = or + bonus objets + PV restants${hero.killedDragon ? ' + bonus dragon' : ''}</div>
     <div id="score-save-status" class="score-save-status"></div>`,
    `${hero.name} peut entrer dans le Hall of Fame.`,
    [
      {label:'💾 Enregistrer', fn:()=>submitScore()},
      {label:'Rejouer', fn:()=>showSetup(), primary:false}
    ]
  );
}

async function submitScore(){
  const firstName=(document.getElementById('score-firstname')?.value || '').trim();
  const lastName=(document.getElementById('score-lastname')?.value || '').trim();
  const status=document.getElementById('score-save-status');
  if(!firstName || !lastName){
    if(status){
      status.textContent='Nom et prénom sont obligatoires.';
      status.className='score-save-status err';
    }
    return;
  }
  try{
    const res=await fetch('/api/highscores',{
      method:'POST',
      headers:{'Content-Type':'application/json'},
      body:JSON.stringify({...pendingScorePayload, firstName, lastName})
    });
    const data=await res.json();
    if(!res.ok) throw new Error(data.error || 'Erreur pendant la sauvegarde');
    await fetchHighscores();
    closeModal();
    showModal(
      '✅ Score enregistré',
      '',
      `${firstName} ${lastName} rejoint le Hall of Fame avec ${pendingScorePayload.score} points.`,
      [{label:'Rejouer', fn:()=>showSetup()}]
    );
  }catch(err){
    if(status){
      status.textContent=err.message || 'Erreur pendant la sauvegarde.';
      status.className='score-save-status err';
    }
    console.error(err);
  }
}


