//  BOARD INIT
// ══════════════════════════════════════════
function initBoard(){
  G.board=[];
  for(let r=0;r<BS;r++){G.board.push([]);for(let c=0;c<BS;c++)G.board[r].push({type:'hidden',revealed:false,content:null});}
  [[0,4],[8,4],[4,0],[4,8]].forEach(([r,c])=>{G.board[r][c]={type:'exit',revealed:true,content:null};});
  G.board[CENTER][CENTER]={type:'castle',revealed:true,content:null};
  [[7,1],[7,7],[1,1],[1,7]].forEach(([r,c])=>{G.board[r][c]={type:'start',revealed:true,content:null};});
  const pool={outer:[],mid:[],inner:[]};
  for(let i=0;i<20;i++)pool.outer.push('corridor');
  for(let i=0;i<10;i++)pool.outer.push('room');
  for(let i=0;i<5;i++) pool.outer.push('treasure');
  for(let i=0;i<4;i++) pool.outer.push('trap');
  for(let i=0;i<3;i++) pool.outer.push('monster');
  for(let i=0;i<8;i++) pool.mid.push('corridor');
  for(let i=0;i<8;i++) pool.mid.push('room');
  for(let i=0;i<5;i++) pool.mid.push('treasure');
  for(let i=0;i<5;i++) pool.mid.push('trap');
  for(let i=0;i<4;i++) pool.mid.push('monster');
  for(let i=0;i<3;i++) pool.inner.push('room');
  for(let i=0;i<3;i++) pool.inner.push('treasure');
  for(let i=0;i<3;i++) pool.inner.push('trap');
  for(let i=0;i<3;i++) pool.inner.push('monster');
  const shuffle=a=>{for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;};
  Object.values(pool).forEach(shuffle);
  const adjMon=(r,c)=>DIRS.some(d=>{const nr=r+d.r,nc=c+d.c;return nr>=0&&nr<BS&&nc>=0&&nc<BS&&G.board[nr][nc].type==='monster';});
  for(let r=0;r<BS;r++)for(let c=0;c<BS;c++){
    const cell=G.board[r][c];if(cell.type!=='hidden')continue;
    const dist=Math.abs(r-CENTER)+Math.abs(c-CENTER);
    let p=dist<=1?pool.inner:dist<=3?pool.mid:pool.outer;
    let chosen='corridor';
    for(let i=0;i<p.length;i++){if(p[i]==='monster'&&adjMon(r,c))continue;chosen=p[i];p.splice(i,1);break;}
    cell.type=chosen;cell.revealed=false;
  }
}

function revealCell(r,c){
  if(G.board[r][c].revealed)return;
  G.board[r][c].revealed=true;
  setTimeout(()=>{const el=document.querySelector(`.cell[data-r="${r}"][data-c="${c}"]`);if(el){el.className=`cell tile-${G.board[r][c].type}`;el.classList.add('revealing');updateCellInner(el,r,c);}},10);
}

