function buildTooltip(r,c){
  const cell=G.board[r][c];
  const heroes=G.heroes.filter(h=>h.r===r&&h.c===c&&!h.dead);
  // Cases non révélées : pas de spoil sur le type
  if(!cell.revealed){
    return `<div class="tooltip-icon">🌑</div><div class="tooltip-title">Inexploré</div><div class="tooltip-body">L'obscurité vous cache ce qui attend ici.</div>`;
  }
  const info=TILE_INFO[cell.type]||TILE_INFO.hidden;
  return `<div class="tooltip-icon">${info.icon}</div><div class="tooltip-title">${info.name}</div><div class="tooltip-body">${info.desc}</div><span class="tooltip-badge ${info.cls}">${info.badge}</span>${cell.content==='looted'?'<div style="color:#777;font-size:10px;margin-top:3px">✓ Fouillée</div>':''}${heroes.length?`<div style="margin-top:4px;color:var(--gold2);font-size:10px">${heroes.map(h=>h.emoji+' '+h.name).join(', ')}</div>`:''}`;
}

// Map tile types to their image asset
const TILE_IMG_MAP = {
  start:    TILE_IMGS.camps,
  castle:   TILE_IMGS.antre,
  monster:  TILE_IMGS.combat,
  trap:     TILE_IMGS.piege,
  treasure: TILE_IMGS.tresor,
  corridor: TILE_IMGS.couloir,
  room:     TILE_IMGS.salle,
  exit:     TILE_IMGS.porte,
};

function updateCellInner(div,r,c){
  const cell=G.board[r][c];
  let inner=div.querySelector('.cell-inner');
  if(!inner){inner=document.createElement('div');inner.className='cell-inner';div.appendChild(inner);}

  // Apply background image when revealed
  if(cell.revealed && TILE_IMG_MAP[cell.type]){
    inner.style.backgroundImage=`url('${TILE_IMG_MAP[cell.type]}')`;
    inner.style.backgroundSize='cover';
    inner.style.backgroundPosition='center';
  } else {
    inner.style.backgroundImage='';
  }

  // Icons uniquement sur monstre / trésor / piège — pas sur château, sortie, couloir, salle, camp
  const icons={monster:'💀',treasure:'💎',trap:'⚠'};
  const ico=cell.content==='looted'?'':(icons[cell.type]||'');

  if(!cell.revealed){
    // BROUILLARD DE GUERRE — case noire opaque, sans image ni texte
    inner.style.backgroundImage='';
    inner.innerHTML='';
  } else if(ico){
    inner.innerHTML=`<div class="tile-icon-overlay"><span style="font-size:20px;pointer-events:none;filter:drop-shadow(0 2px 4px rgba(0,0,0,.9))">${ico}</span></div>`;
  } else {
    inner.innerHTML='';
  }

  G.heroes.filter(h=>h.r===r&&h.c===c&&!h.dead).forEach((h,i)=>{
    const tok=document.createElement('div');tok.className='board-hero';tok.id='tok-'+h.id;
    tok.style.cssText=`background:${h.color};left:${3+i*24}px;bottom:3px`;tok.textContent=h.name[0];inner.appendChild(tok);
  });
  let tip=div.querySelector('.cell-tooltip');
  if(!tip){tip=document.createElement('div');tip.className='cell-tooltip';div.appendChild(tip);}
  tip.innerHTML=buildTooltip(r,c);
}

function renderBoard(){
  const bd=document.getElementById('board');bd.innerHTML='';
  for(let r=0;r<BS;r++)for(let c=0;c<BS;c++){
    const div=document.createElement('div');
    const cell=G.board[r][c];
    // Unrevealed cells always render as tile-hidden — no color/type hint
    div.className=`cell ${cell.revealed ? 'tile-'+cell.type : 'tile-hidden'}`;
    div.dataset.r=r;div.dataset.c=c;
    updateCellInner(div,r,c);
    const cur=G.heroes[G.currentHero];
    if(cur&&r===cur.r&&c===cur.c){const inn=div.querySelector('.cell-inner');if(inn)inn.style.boxShadow=`inset 0 0 0 2px ${cur.color},0 0 12px ${cur.color}99`;}
    bd.appendChild(div);
  }
}

function refreshCell(r,c){
  const div=document.querySelector(`.cell[data-r="${r}"][data-c="${c}"]`);
  if(!div)return;
  const cell=G.board[r][c];
  div.className=`cell ${cell.revealed ? 'tile-'+cell.type : 'tile-hidden'}`;
  updateCellInner(div,r,c);
  const cur=G.heroes[G.currentHero];
  if(cur&&r===cur.r&&c===cur.c){const inn=div.querySelector('.cell-inner');if(inn)inn.style.boxShadow=`inset 0 0 0 2px ${cur.color},0 0 12px ${cur.color}99`;}
}

function renderHeroes(){
  const el=document.getElementById('hero-list');el.innerHTML='';
  G.heroes.forEach((h,i)=>{
    const card=document.createElement('div');
    card.className='hero-card'+(i===G.currentHero?' active':'')+(h.dead?' dead':'');
    const bP=Math.max(0,Math.round(h.body/h.bodyMax*100));
    card.innerHTML=`<div style="display:flex;align-items:center;gap:6px;margin-bottom:4px"><div style="width:22px;height:22px;border-radius:50%;background:${h.color};border:2px solid var(--gold);display:flex;align-items:center;justify-content:center;font-size:11px">${h.emoji}</div><div><div class="hero-name">${h.name}</div><div class="hero-class">${h.cls}</div></div></div><div class="stat-row"><span class="stat-label">Corps</span><span class="stat-val" style="color:${h.body<=2?'#ff6060':'var(--parchment)'}">${h.body}/${h.bodyMax}</span></div><div class="stat-bar-bg"><div class="stat-bar bar-body" style="width:${bP}%"></div></div><div class="stat-row"><span class="stat-label">🧪 Potions / 🎲 Relances</span><span class="stat-val">${h.potions} / ${h.rerolls}</span></div><div class="stat-row"><span class="stat-label">Combat / Chance</span><span class="stat-val">${h.combat} / ${h.luck}</span></div><div class="stat-row"><span class="stat-label">Or</span><span class="stat-val">${h.gold} 💰</span></div>${h.items.length?`<div class="hero-items">${h.items.map(x=>x.emoji+' '+x.name).join(' · ')}</div>`:''}${h.dead?'<div style="color:#f09090;font-size:11px;margin-top:4px">☠ Mort dans le donjon</div>':''}`;
    el.appendChild(card);
  });
}

function renderTimeTrack(){
  const el=document.getElementById('time-track');el.innerHTML='';
  for(let i=0;i<TIME_MAX;i++){const s=document.createElement('div');s.id='tseg'+i;s.className='time-seg'+(i<G.timeTrack?' passed':i===G.timeTrack?' current':i>=12?' night-warn':'');el.appendChild(s);}
  const lbl=document.getElementById('time-label');
  if(G.timeTrack>=TIME_MAX){lbl.textContent='🌑 La nuit est tombée !';lbl.style.color='#8080c0';document.getElementById('night-overlay').classList.add('active');}
  else{lbl.textContent=`Tour ${G.timeTrack+1}/${TIME_MAX} — ${TIME_MAX-G.timeTrack} avant la nuit`;lbl.style.color='#aaa';}
}
function advanceTimeAnim(){const s=document.getElementById('tseg'+(G.timeTrack-1));if(s){s.classList.add('pulse');setTimeout(()=>s.classList.remove('pulse'),700);}}

