// ══════════════════════════════════════════
//  DICE HELPERS
// ══════════════════════════════════════════
function rollD6(){return Math.floor(Math.random()*6)+1;}
function rollD3(){return Math.floor(Math.random()*3)+1;}

// ══════════════════════════════════════════
//  SMART DIRECTION SYSTEM
// ══════════════════════════════════════════
function pickDirections(h){
  const mv={N:[-1,0],S:[1,0],E:[0,1],W:[0,-1]};
  const all=['N','S','E','W'];
  const weights=all.map(d=>{
    const[dr,dc]=mv[d];const nr=h.r+dr,nc=h.c+dc;
    if(nr<0||nr>=BS||nc<0||nc>=BS)return 0;
    const cell=G.board[nr][nc];let w=10;
    if(!cell.revealed)w+=8;
    const toC=Math.abs(nr-CENTER)+Math.abs(nc-CENTER);
    const curD=Math.abs(h.r-CENTER)+Math.abs(h.c-CENTER);
    if(toC<curD)w+=4;
    if(h.lastDir&&d===h.lastDir)w-=5;
    if(h.visited&&h.visited[nr+','+nc])w-=6;
    return Math.max(0,w);
  });
  const pick=(ex)=>{
    const pool=all.filter((_,i)=>weights[i]>0&&_!==ex);
    if(!pool.length)return all.find((_,i)=>weights[i]>0&&_!==ex)||all[0];
    let sum=pool.reduce((s,d)=>s+weights[all.indexOf(d)],0),r=Math.random()*sum;
    for(const d of pool){r-=weights[all.indexOf(d)];if(r<=0)return d;}
    return pool[pool.length-1];
  };
  const d1=pick(null);return[d1,pick(d1)];
}

function renderDirectionChoice(){
  if(!G_dirChoice)return;
  const{d1,d2,steps}=G_dirChoice;
  const el=document.getElementById('actions');el.innerHTML='';
  document.getElementById('action-label').textContent='CHOISISSEZ UNE DIRECTION';
  const dirLbl={N:'Nord',S:'Sud',E:'Est',W:'Ouest'};
  [d1,d2].forEach(dir=>el.appendChild(mkBtn(DIR_ARR[dir],`${dirLbl[dir]} (${steps} pas)`,()=>confirmMove(dir,steps),true)));
}

async function rollMoveDice(){
  const h=G.heroes[G.currentHero];if(!h.visited)h.visited={};
  const steps=rollD3();const[d1,d2]=pickDirections(h);
  renderDice([d1,d2,steps]);
  log(`${h.name} : choisir ${DIR_ARR[d1]} ou ${DIR_ARR[d2]}, ${steps} pas`);
  G_dirChoice={d1,d2,steps};renderDirectionChoice();
}

async function confirmMove(dir,steps){
  G_dirChoice=null;document.getElementById('action-label').textContent='ACTIONS DISPONIBLES';
  const h=G.heroes[G.currentHero];
  const mv={N:[-1,0],S:[1,0],E:[0,1],W:[0,-1]};const[dr,dc]=mv[dir];
  const fr=h.r,fc=h.c;let r=h.r,c=h.c;
  for(let i=0;i<steps;i++){const nr=r+dr,nc=c+dc;if(nr<0||nr>=BS||nc<0||nc>=BS)break;r=nr;c=nc;if(!G.board[r][c].revealed)revealCell(r,c);}
  h.lastDir=dir;h.visited[r+','+c]=(h.visited[r+','+c]||0)+1;
  await animateHeroMove(h,fr,fc,r,c);
  h.r=r;h.c=c;G.moved=true;G.phase='event';G.eventDone=false;
  const cell=G.board[r][c],info=TILE_INFO[cell.type]||TILE_INFO.hidden;
  log(`${h.name} → (${r},${c}) : ${info.name}`,cell.type==='monster'?'danger':cell.type==='treasure'?'success':'');
  if(['monster','treasure','trap','castle','exit'].includes(cell.type)){
    let body=info.desc;
    if(cell.type==='exit')body=`Vous êtes à la sortie !\n\nButin actuel : ${h.gold} 💰 | ${h.items.length} objet(s)\n\nPartez maintenant ou retournez chercher plus de richesses…`;
    showModal(info.name,'',body,[{label:'Continuer',fn:()=>renderAll()}]);
  }else renderAll();
}

// ══════════════════════════════════════════
//  HERO MOVEMENT ANIMATION
// ══════════════════════════════════════════
function getTokenPos(r,c){
  const cells=document.querySelectorAll('.cell');const idx=r*BS+c,cell=cells[idx];
  if(!cell)return{x:0,y:0};const rect=cell.getBoundingClientRect();
  return{x:rect.left+rect.width/2-13,y:rect.top+rect.height/2-13};
}

function animateHeroMove(hero,fr,fc,tr,tc){
  return new Promise(resolve=>{
    const from=getTokenPos(fr,fc);
    const ft=document.createElement('div');
    ft.style.cssText=`position:fixed;z-index:100;width:26px;height:26px;border-radius:50%;background:${hero.color};border:2px solid white;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:700;font-family:'Cinzel',serif;pointer-events:none;transition:left .45s cubic-bezier(.34,1.56,.64,1),top .45s cubic-bezier(.34,1.56,.64,1);box-shadow:0 0 14px ${hero.color}99;left:${from.x}px;top:${from.y}px`;
    ft.textContent=hero.name[0];document.body.appendChild(ft);
    const dr=Math.sign(tr-fr),dc=Math.sign(tc-fc);let cr=fr,cc=fc;
    while(cr!==tr||cc!==tc){
      if(cr!==tr)cr+=dr;else cc+=dc;
      if(cr!==tr||cc!==tc){const pos=getTokenPos(cr,cc);const t=document.createElement('div');t.className='trail';t.style.cssText=`left:${pos.x+9}px;top:${pos.y+9}px;background:${hero.color};`;document.body.appendChild(t);setTimeout(()=>t.remove(),800);}
    }
    setTimeout(()=>{const to=getTokenPos(tr,tc);ft.style.left=to.x+'px';ft.style.top=to.y+'px';},30);
    setTimeout(()=>{ft.remove();refreshCell(fr,fc);refreshCell(tr,tc);resolve();},520);
  });
}

function usePotion(){
  const h=G.heroes[G.currentHero];
  if(h.potions<=0){log('Plus de potions !','danger');return;}
  h.potions--;
  const heal=Math.min(3, h.bodyMax-h.body);
  h.body+=heal;
  flashBoard('green');
  const tok=document.getElementById('tok-'+h.id);spawnFloatNumber('+'+heal+'♥','green',tok);
  log(`🧪 ${h.name} boit une potion et récupère ${heal} Corps. (${h.potions} restante${h.potions!==1?'s':''})`, 'success');
  renderAll();
}

function useReroll(){
  const h=G.heroes[G.currentHero];
  if(h.rerolls<=0){log('Plus de relances !','danger');return;}
  if(G.phase!=='move'){log('La relance s\'utilise uniquement lors du déplacement !','danger');return;}
  h.rerolls--;
  G_dirChoice=null;
  log(`🎲 ${h.name} relance les dés ! (${h.rerolls} restante${h.rerolls!==1?'s':''})`, 'important');
  rollMoveDice();
}

// ══════════════════════════════════════════
//  EVENTS
// ══════════════════════════════════════════
function doTreasure(){
  const h=G.heroes[G.currentHero];const cell=G.board[h.r][h.c];
  const tr=TREASURES[Math.floor(Math.random()*TREASURES.length)];
  cell.content='looted';cell.type='corridor';
  h.gold+=tr.gold;
  if(tr.combatBonus)h.combat+=tr.combatBonus;
  if(tr.bodyBonus){h.bodyMax+=tr.bodyBonus;h.body+=tr.bodyBonus;}
  if(tr.potionBonus)h.potions+=tr.potionBonus;if(tr.rerollBonus)h.rerolls+=tr.rerollBonus;
  if(tr.luckBonus)h.luck+=tr.luckBonus;
  if(tr.heal)h.body=Math.min(h.bodyMax,h.body+tr.heal);
  h.items.push({name:tr.name,emoji:tr.emoji});
  log(`${h.name} trouve : ${tr.emoji} ${tr.name} — ${tr.bonus}`,'success');
  const cr=document.getElementById('card-reveal');
  cr.className='show';
  cr.innerHTML=`<div class="card-icon">${tr.emoji}</div><div class="card-name">${tr.name}</div><div class="card-desc">"${tr.desc}"</div><div class="card-bonus">${tr.bonus}</div>`;
  setTimeout(()=>cr.className='',4500);
  G.eventDone=true;G.phase='end';renderAll();
}

function doTrap(){
  const h=G.heroes[G.currentHero];
  const trap=TRAPS[Math.floor(Math.random()*TRAPS.length)];
  G.board[h.r][h.c].type='corridor';
  if(trap.bodyLoss)h.body-=trap.bodyLoss;
  if(trap.rerollLoss)h.rerolls=Math.max(0,h.rerolls-trap.rerollLoss);
  if(trap.luckLoss)h.luck-=trap.luckLoss;
  log(`${h.name} déclenche : ${trap.emoji} ${trap.name} ! ${trap.effect}`,'danger');
  flashBoard('red');shakeToken(h.id);
  if(trap.bodyLoss){const tok=document.getElementById('tok-'+h.id);spawnFloatNumber('-'+trap.bodyLoss+'♥','red',tok);}
  showModal(
    trap.emoji+' '+trap.name,'',
    `${trap.effect}\n\nCorps restant : ${Math.max(0,h.body)}/${h.bodyMax}`,
    [{label:'Continuer',fn:()=>{G.eventDone=true;G.phase='end';checkDeath(h);renderAll();}}]
  );
}

function testLuck(){
  const h=G.heroes[G.currentHero];const roll=rollD6();renderDice([roll]);
  if(roll<=h.luck){
    log(`${h.name} teste la Chance (${roll} ≤ ${h.luck}) : succès !`,'success');
    showModal('🍀 Chance !','',`Jet de chance : ${roll} ≤ ${h.luck}\nLe piège est désamorcé !`,[{label:'Continuer',fn:()=>{G.board[h.r][h.c].type='corridor';G.eventDone=true;G.phase='end';renderAll();}}]);
  }else{
    log(`${h.name} teste la Chance (${roll} > ${h.luck}) : échec !`,'danger');doTrap();
  }
}

function startCombat(monster){
  const h=G.heroes[G.currentHero];
  // Guard: if called with a MouseEvent or non-monster object, ignore the argument
  const validMonster=(monster&&monster.name&&typeof monster.combat==='number')?monster:null;
  const m=validMonster||MONSTERS[Math.floor(Math.random()*(MONSTERS.length-1))];
  G.combat={monster:m,rounds:0};G.phase='combat';
  log(`⚔ ${h.name} affronte ${m.emoji} ${m.name} !`,'danger');
  showModal(
    `${m.emoji} ${m.name}`,
    `<div style="color:#aaa;font-size:12px;font-style:italic;margin-bottom:10px">${m.desc}</div>
     <div style="display:flex;gap:12px;justify-content:center;margin-bottom:8px">
       <div style="background:var(--stone3);border-radius:4px;padding:6px 12px;font-family:'Cinzel',serif;font-size:11px"><div style="color:#999;font-size:9px;letter-spacing:1px;margin-bottom:2px">COMBAT</div><div style="color:var(--blood2);font-size:18px;font-weight:700">${m.combat}</div></div>
       <div style="background:var(--stone3);border-radius:4px;padding:6px 12px;font-family:'Cinzel',serif;font-size:11px"><div style="color:#999;font-size:9px;letter-spacing:1px;margin-bottom:2px">DÉGÂTS</div><div style="color:#ff9090;font-size:18px;font-weight:700">${m.damage}</div></div>
       <div style="background:var(--stone3);border-radius:4px;padding:6px 12px;font-family:'Cinzel',serif;font-size:11px"><div style="color:#999;font-size:9px;letter-spacing:1px;margin-bottom:2px">BUTIN</div><div style="color:var(--gold2);font-size:18px;font-weight:700">${m.gold}💰</div></div>
     </div>`,
    `Votre combat : ${h.combat}  |  Vos Corps : ${h.body}/${h.bodyMax}`,
    [{label:'⚔ Au combat !',fn:()=>renderAll()}]
  );
}

// ══════════════════════════════════════════
//  SALLE DU DRAGON — Stop ou Encore
// ══════════════════════════════════════════

// Deck de cartes de la salle du dragon : trésors + événements "dragon"
const DRAGON_ROOM_CARDS = [
  // Trésors précieux (toujours disponibles)
  {type:'treasure', name:'Lingot d\'or maudit',    desc:'L\'or du dragon brûle les mains...',  gold:80,  emoji:'🪙'},
  {type:'treasure', name:'Gemme de dragon',         desc:'Pierre précieuse arrachée au trésor.', gold:120, emoji:'💎'},
  {type:'treasure', name:'Épée draconique',         desc:'Forgée dans le souffle du dragon.',   gold:90,  combatBonus:3, emoji:'⚔'},
  {type:'treasure', name:'Écaille de dragon',       desc:'Armure légère et quasi indestructible.',gold:100, bodyBonus:2, emoji:'🛡'},
  {type:'treasure', name:'\u0152il de dragon',           desc:'Un cristal qui voit dans l\'obscurité.', gold:110, luckBonus:2, emoji:'👁'},
  {type:'treasure', name:'Calice de vigueur',       desc:'Un élixir mystérieux aux vertus puissantes.', gold:70, potionBonus:2, emoji:'🍷'},
  {type:'treasure', name:'Sceptre ancien',           desc:'Symbole du pouvoir draconique.',      gold:150, emoji:'👑'},
  {type:'treasure', name:'Parchemin runique',        desc:'Des runes qui accordent une seconde chance.', gold:85, rerollBonus:2, emoji:'📜'},
  // Cartes neutres (le dragon grogne mais ne se réveille pas)
  {type:'groan', name:'Grognement...',    desc:'Le dragon se retourne dans son sommeil. Son souffle chaud vous effleure.',    emoji:'😤'},
  {type:'groan', name:'Mouvement suspect', desc:'Une griffe racle le sol. Le dragon bouge... mais n\'ouvre pas les yeux.',    emoji:'🐾'},
  {type:'groan', name:'Fumée de narines', desc:'Un nuage de fumée s\'échappe des narines du dragon. Il rêve de carnage.',    emoji:'💨'},
];

// Probabilité de réveil : augmente avec chaque tirage dans la salle
// Tirage 1 : 10%, 2 : 20%, 3 : 35%, 4 : 55%, 5 : 75%, 6+ : 90%
const DRAGON_WAKE_ODDS = [0.10, 0.20, 0.35, 0.55, 0.75, 0.90];

function enterCastle(){
  const h=G.heroes[G.currentHero];
  if(!h.castleDraws) h.castleDraws=0;
  log(`🏰 ${h.name} pénètre dans la salle du Dragon…`,'important');
  showModal(
    '🏰 La Salle du Dragon',
    `<div style="font-size:32px;text-align:center;margin:8px 0">🐉</div>
     <div style="color:#aaa;font-size:12px;font-style:italic;text-align:center;margin-bottom:10px">Le Dragon Dragonfire sommeille sur son trésor.<br>Un trésor immense… si vous osez le prendre.</div>`,
    `L'air est lourd de soufre. Vos pas résonnent sur les dalles couvertes d'or.

Chaque pièce que vous prenez risque de réveiller la bête.
Plus vous tardez, plus le danger est grand.`,
    [{label:'🪙 Tirer une carte', fn:()=>drawDragonCard()}]
  );
}

function drawDragonCard(){
  const h=G.heroes[G.currentHero];
  if(!h.castleDraws) h.castleDraws=0;

  // Vérifier le réveil du dragon AVANT de tirer la carte
  const wakeOdds = DRAGON_WAKE_ODDS[Math.min(h.castleDraws, DRAGON_WAKE_ODDS.length-1)];
  const wakes = Math.random() < wakeOdds;

  h.castleDraws++;

  if(wakes){
    // LE DRAGON SE RÉVEILLE
    dragonAwakens(h, wakeOdds);
    return;
  }

  // Tirage d'une carte (favorise les trésors en début, équilibre ensuite)
  const treasureCards = DRAGON_ROOM_CARDS.filter(c=>c.type==='treasure');
  const groanCards = DRAGON_ROOM_CARDS.filter(c=>c.type==='groan');
  // Plus on tire, plus on peut tomber sur un grognement
  const treasureWeight = Math.max(0.3, 0.85 - h.castleDraws * 0.1);
  const card = Math.random() < treasureWeight
    ? treasureCards[Math.floor(Math.random()*treasureCards.length)]
    : groanCards[Math.floor(Math.random()*groanCards.length)];

  // Appliquer les effets trésor
  if(card.type==='treasure'){
    h.gold += card.gold;
    if(card.combatBonus) h.combat += card.combatBonus;
    if(card.bodyBonus){h.bodyMax+=card.bodyBonus;h.body+=card.bodyBonus;}
    if(card.potionBonus)h.potions+=card.potionBonus;if(card.rerollBonus)h.rerolls+=card.rerollBonus;
    if(card.luckBonus) h.luck += card.luckBonus;
    h.items.push({name:card.name, emoji:card.emoji});
    log(`${h.name} saisit : ${card.emoji} ${card.name} (+${card.gold}💰)`,'success');
  } else {
    log(`${h.name} : "${card.name}" — le dragon grogne mais dort encore…`,'important');
  }

  // Prochain risque
  const nextOdds = DRAGON_WAKE_ODDS[Math.min(h.castleDraws, DRAGON_WAKE_ODDS.length-1)];
  const nextPct = Math.round(nextOdds*100);
  const dangerColor = nextPct >= 55 ? '#ff6060' : nextPct >= 35 ? '#ffaa40' : '#ffee80';

  const cardVisual = card.type==='treasure'
    ? `<div style="background:var(--stone3);border:1px solid var(--gold);border-radius:6px;padding:10px;text-align:center;margin-bottom:10px">
         <div style="font-size:32px;margin-bottom:4px">${card.emoji}</div>
         <div style="font-family:'Cinzel',serif;color:var(--gold2);font-size:13px">${card.name}</div>
         <div style="font-size:11px;color:#aaa;font-style:italic;margin-top:3px">${card.desc}</div>
         <div style="color:var(--emerald2);font-size:12px;font-weight:600;margin-top:6px">+${card.gold} 💰${card.combatBonus?` +${card.combatBonus} Combat`:''}${card.bodyBonus?` +${card.bodyBonus} Corps`:''}${card.potionBonus?` +${card.potionBonus} Potion`:''}${card.rerollBonus?` +${card.rerollBonus} Relance`:''}${card.luckBonus?` +${card.luckBonus} Chance`:''}</div>
       </div>`
    : `<div style="background:#200808;border:1px solid var(--blood2);border-radius:6px;padding:10px;text-align:center;margin-bottom:10px">
         <div style="font-size:32px;margin-bottom:4px">${card.emoji}</div>
         <div style="font-family:'Cinzel',serif;color:#ff9090;font-size:13px">${card.name}</div>
         <div style="font-size:11px;color:#aaa;font-style:italic;margin-top:3px">${card.desc}</div>
       </div>`;

  const riskBar = buildRiskBar(nextOdds);

  showModal(
    card.type==='treasure' ? `${card.emoji} Trésor trouvé !` : `${card.emoji} ${card.name}`,
    cardVisual + riskBar,
    `Butin total : ${h.gold} 💰  |  Tirage n°${h.castleDraws}
Prochain tirage : risque de réveil ${nextPct}%`,
    [
      {label:'🪙 Tirer encore', fn:()=>drawDragonCard()},
      {label:'🏃 Fuir avec le butin', fn:()=>leaveCastle(h), primary:false},
    ]
  );
}

function buildRiskBar(odds){
  const pct = Math.round(odds*100);
  const filled = Math.round(odds*10);
  const color = pct >= 55 ? '#ff3030' : pct >= 35 ? '#ff8020' : '#ffe040';
  let segs='';
  for(let i=0;i<10;i++){
    const on = i < filled;
    segs += `<div style="flex:1;height:10px;border-radius:2px;background:${on?color:'#1a1510'};border:1px solid #333;transition:all .3s"></div>`;
  }
  return `<div style="margin-bottom:8px">
    <div style="font-family:'Cinzel',serif;font-size:9px;letter-spacing:1px;color:#888;margin-bottom:4px">RISQUE DE RÉVEIL DU DRAGON</div>
    <div style="display:flex;gap:2px">${segs}</div>
    <div style="font-size:10px;color:${color};text-align:right;margin-top:2px;font-family:'Cinzel',serif">${pct}%</div>
  </div>`;
}

function leaveCastle(h){
  h.castleDraws=0;
  G.eventDone=true;G.phase='end';
  log(`${h.name} quitte la salle du Dragon avec son butin !`,'success');
  renderAll();
}

function dragonAwakens(h, odds){
  const dragon = MONSTERS[5]; // Dragon Dragonfire
  log(`🐉 LE DRAGON SE RÉVEILLE ! ${h.name} est pris au piège !`,'danger');
  flashBoard('red');

  // Animation : flashs rouges répétés
  let flashes=0;
  const interval=setInterval(()=>{
    flashBoard('red');
    flashes++;
    if(flashes>=3) clearInterval(interval);
  },400);

  showModal(
    '🐉 LE DRAGON SE RÉVEILLE !',
    `<div style="font-size:56px;text-align:center;margin:8px 0;animation:hpLowPulse .5s infinite">🐉</div>
     <div style="background:#200808;border:1px solid var(--blood2);border-radius:6px;padding:10px;text-align:center;margin-bottom:10px">
       <div style="font-family:'Cinzel',serif;color:#ff4040;font-size:14px;margin-bottom:6px">DRAGONFIRE S'ÉVEILLE !</div>
       <div style="color:#aaa;font-size:12px;font-style:italic">${dragon.desc}</div>
       <div style="display:flex;gap:12px;justify-content:center;margin-top:8px">
         <div style="background:var(--stone3);border-radius:4px;padding:6px 12px;font-family:'Cinzel',serif;font-size:11px"><div style="color:#999;font-size:9px;letter-spacing:1px;margin-bottom:2px">COMBAT</div><div style="color:var(--blood2);font-size:18px;font-weight:700">${dragon.combat}</div></div>
         <div style="background:var(--stone3);border-radius:4px;padding:6px 12px;font-family:'Cinzel',serif;font-size:11px"><div style="color:#999;font-size:9px;letter-spacing:1px;margin-bottom:2px">DÉGÂTS</div><div style="color:#ff9090;font-size:18px;font-weight:700">${dragon.damage}</div></div>
       </div>
     </div>`,
    `Pas de fuite possible. ${h.name} doit se battre… ou périr.

Butin engrangé : ${h.gold} 💰`,
    [{label:'⚔ Affronter le Dragon !', fn:()=>{ h.castleDraws=0; startCombat(dragon); }}]
  );
}

function resolveCombat(){
  const h=G.heroes[G.currentHero];const{monster}=G.combat;
  const hr=rollD6(),mr=rollD6();renderDice([hr,'VS',mr]);
  const ht=hr+h.combat,mt=mr+monster.combat;G.combat.rounds++;

  const scoreboard=`
    <div class="combat-scoreboard">
      <div class="combat-side">
        <div class="combat-side-name">${h.emoji} ${h.name}</div>
        <div class="combat-side-roll" style="color:var(--gold2)">${DICE_FACES[hr]}</div>
        <div class="combat-side-total" style="color:var(--parchment2)">${hr} + ${h.combat} = <strong>${ht}</strong></div>
      </div>
      <div class="combat-vs">VS</div>
      <div class="combat-side">
        <div class="combat-side-name">${monster.emoji} ${monster.name}</div>
        <div class="combat-side-roll" style="color:#f09090">${DICE_FACES[mr]}</div>
        <div class="combat-side-total" style="color:var(--parchment2)">${mr} + ${monster.combat} = <strong>${mt}</strong></div>
      </div>
    </div>`;

  if(ht>mt){
    // VICTOIRE
    flashBoard('green');
    const tok=document.getElementById('tok-'+h.id);spawnFloatNumber('+'+monster.gold+'💰','gold',tok);
    h.gold+=monster.gold;G.board[h.r][h.c].type='corridor';G.board[h.r][h.c].content='looted';
    G.combat=null;G.phase='end';G.eventDone=true;
    const isDragon=monster.id==='dragon';
    if(isDragon) h.killedDragon=true;
    log(`${h.name} (${ht}) bat ${monster.name} (${mt}) ! +${monster.gold} or`,'success');
    showModal(
      isDragon?'🏆 LE DRAGON EST VAINCU !':'🏆 Victoire !',
      scoreboard+`<div class="combat-result-badge badge-win">${isDragon?'LÉGENDAIRE':'VICTOIRE'}</div>`,
      isDragon
        ? `${h.name} terrasse le Dragon Dragonfire !\nUne victoire que les bardes chanteront pendant des siècles !\n\nButin total : ${h.gold} 💰`
        : `${h.name} triomphe du ${monster.name} !\nButin : +${monster.gold} pièces d'or`,
      [{label:'Continuer',fn:()=>renderAll()}]);
  }else if(mt>ht){
    // DÉFAITE
    flashBoard('red');shakeToken(h.id);shakeHpBar();
    const tok=document.getElementById('tok-'+h.id);spawnFloatNumber('-'+monster.damage+'♥','red',tok);
    h.body-=monster.damage;
    log(`${h.name} (${ht}) vs (${mt}) : −${monster.damage} Corps`,'danger');
    if(h.body<=0){
      h.dead=true;G.combat=null;G.phase='end';log(`☠ ${h.name} est mort !`,'danger');
      showModal('☠ Mort au combat',scoreboard+`<div class="combat-result-badge badge-lose">DÉFAITE</div>`,
        `${h.name} tombe, vaincu par le ${monster.name}.`,
        [{label:'Continuer',fn:()=>{checkAllDead();renderAll();}}]);
    }else{
      const canFlee=!monster.id||monster.id!=='dragon';
      showModal('💔 Blessure !',scoreboard+`<div class="combat-result-badge badge-lose">BLESSÉ — ${monster.damage} Corps</div>`,
        `Corps restant : ${h.body}/${h.bodyMax}\n\nLe combat continue…`,
        canFlee
          ? [{label:'⚔ Attaquer encore',fn:()=>renderAll()},{label:'🏃 Fuir',fn:()=>fleeCombat(),primary:false}]
          : [{label:'⚔ Attaquer encore — pas de retraite !',fn:()=>renderAll()}]);
    }
  }else{
    log(`Égalité (${ht} vs ${mt}) — le combat continue…`);
    showModal('🤝 Égalité',scoreboard+`<div class="combat-result-badge badge-tie">ÉGALITÉ</div>`,
      'Aucun des deux ne parvient à prendre le dessus. Le combat continue…',
      [{label:'⚔ Attaquer encore',fn:()=>renderAll()},{label:'🏃 Fuir',fn:()=>fleeCombat(),primary:false}]);
  }
}

function fleeInit(){
  const h=G.heroes[G.currentHero];const roll=rollD6();renderDice([roll]);
  if(roll>=4){const adj=DIRS.map(d=>({r:h.r+d.r,c:h.c+d.c})).filter(p=>p.r>=0&&p.r<BS&&p.c>=0&&p.c<BS&&G.board[p.r][p.c].type!=='monster');if(adj.length){h.r=adj[0].r;h.c=adj[0].c;}log(`${h.name} fuit (${roll}) !`,'success');G.phase='end';G.eventDone=true;renderAll();}
  else{h.body-=1;log(`${h.name} fuit (${roll}) : échoue ! -1 Corps`,'danger');flashBoard('red');checkDeath(h);renderAll();}
}

function fleeCombat(){
  const h=G.heroes[G.currentHero];const roll=rollD6();renderDice([roll]);
  if(roll>=4){G.combat=null;G.phase='end';G.eventDone=true;log(`${h.name} fuit le combat (${roll}) !`,'success');renderAll();}
  else{const dmg=G.combat.monster.damage;h.body-=dmg;flashBoard('red');shakeToken(h.id);
    log(`${h.name} ne peut pas fuir (${roll}) : -${dmg} Corps`,'danger');
    if(h.body<=0){h.dead=true;G.combat=null;G.phase='end';log(`☠ ${h.name} est mort !`,'danger');checkAllDead();}renderAll();}
}

function escape(){
  const h=G.heroes[G.currentHero];
  const hasLoot=h.gold>0||h.items.length>0;
  const flavor=!hasLoot?`${h.name} sort les mains vides… La honte sera grande.`:h.gold>=150||h.items.length>=3?`Une sortie triomphale ! Les bardes chanteront les exploits de ${h.name} !`:`${h.name} s'échappe avec un butin honnête.`;
  const finalScore=computeScore(h);
  log(`🎉 ${h.name} s'échappe ! ${h.gold} or, ${h.items.length} objets`,'success');
  G.gameOver=true;
  showModal('🎉 VICTOIRE !','',`${flavor}\n\nButin : ${h.gold} 💰\nObjets (${h.items.length}) : ${h.items.map(x=>x.emoji+' '+x.name).join(', ')||'aucun'}\nCorps restant : ${h.body}/${h.bodyMax}\nScore final : ${finalScore}`,
    [{label:'🏆 Enregistrer le score',fn:()=>openScoreSubmission(h)},{label:'Rejouer',fn:()=>showSetup(),primary:false}]);
  renderAll();
}

function checkDeath(h){if(h.body<=0){h.body=0;h.dead=true;log(`☠ ${h.name} est mort !`,'danger');checkAllDead();}}
function checkAllDead(){if(!G.heroes.filter(h=>!h.dead).length){G.gameOver=true;showModal('☠ DÉFAITE','','Tous les héros ont péri.\nLe Dragon règne sans partage…',[{label:'Rejouer',fn:()=>showSetup()}]);}}

function nextHeroTurn(){
  const cur=G.currentHero;let next=(G.currentHero+1)%G.heroes.length,loops=0;
  while(G.heroes[next].dead&&loops<G.heroes.length){next=(next+1)%G.heroes.length;loops++;}
  if(next<=cur){
    G.timeTrack++;G.round++;advanceTimeAnim();log(`— Tour ${G.round} —`,'important');
    if(G.timeTrack>=TIME_MAX){log('🌑 La nuit est tombée !','danger');G.heroes.filter(h=>!h.dead).forEach(h=>{if(Math.random()<.5){h.body--;log(`${h.name} blessé dans l'obscurité ! -1 Corps`,'danger');checkDeath(h);}});}
  }
  G.currentHero=next;G.phase='move';G.moved=false;G.eventDone=false;G.combat=null;G_dirChoice=null;
  renderDice(null);log(`⚔ Tour de ${G.heroes[next].name}…`,'important');renderAll();
}

// ══════════════════════════════════════════
//  SETUP
// ══════════════════════════════════════════
let selectedHeroes=[],numPlayers=1;
function showSetup(){document.getElementById('setup').classList.remove('hidden');document.getElementById('app').style.display='none';selectedHeroes=[];numPlayers=1;renderSetup();
fetchHighscores();fetchHighscores();}

function renderSetup(){
  const picker=document.getElementById('hero-picker');picker.innerHTML='';
  HEROES_DATA.forEach(h=>{
    const div=document.createElement('div');
    div.className='hero-pick'+(selectedHeroes.find(s=>s.id===h.id)?' selected':'');
    div.innerHTML=`<div style="font-size:22px;margin-bottom:4px">${h.emoji}</div><div class="hero-pick-name">${h.name}</div><div class="hero-pick-class">${h.cls}</div><div class="hero-pick-stats">${h.desc}</div>`;
    div.onclick=()=>{const idx=selectedHeroes.findIndex(s=>s.id===h.id);if(idx>=0)selectedHeroes.splice(idx,1);else if(selectedHeroes.length<numPlayers)selectedHeroes.push(h);renderSetup();};
    picker.appendChild(div);
  });
  document.querySelectorAll('.pc-btn').forEach(b=>{
    b.classList.toggle('active',parseInt(b.dataset.n)===numPlayers);
    b.onclick=()=>{numPlayers=parseInt(b.dataset.n);selectedHeroes=selectedHeroes.slice(0,numPlayers);renderSetup();};
  });
  const sb=document.getElementById('start-btn');
  sb.disabled=selectedHeroes.length!==numPlayers;
  sb.textContent=selectedHeroes.length===numPlayers?`⚔ Pénétrer dans le Donjon (${numPlayers} héros)`:`Choisissez encore ${numPlayers-selectedHeroes.length} héros…`;
}

function startGame(){
  const starts=[[7,1],[7,7],[1,1],[1,7]];
  G.heroes=selectedHeroes.map((hd,i)=>({...hd,body:hd.body,bodyMax:hd.body+2,potions:hd.potions,rerolls:hd.rerolls,combatBase:hd.combat,combat:hd.combat,luck:hd.luck,items:[],gold:0,killedDragon:false,r:starts[i][0],c:starts[i][1],dead:false,visited:{},lastDir:null}));
  G.currentHero=0;G.timeTrack=0;G.phase='move';G.gameOver=false;G.round=1;G.combat=null;G.moved=false;G.eventDone=false;G_dirChoice=null;
  initBoard();G.heroes.forEach(h=>{G.board[h.r][h.c].revealed=true;G.board[h.r][h.c].type='start';});
  document.getElementById('setup').classList.add('hidden');document.getElementById('app').style.display='block';
  document.getElementById('night-overlay').classList.remove('active');
  log('⚔ La quête commence !','important');log(`${G.heroes[0].name} ouvre la marche.`);
  renderAll();
  showModal('🏰 Bienvenue dans Dragonfire','',
    `${G.heroes.map(h=>h.emoji+' '+h.name).join(', ')}\nentrent dans le donjon.\n\nSurvivez jusqu'à l'aube… ou mourez dans l'ombre.`,
    [{label:'⚔ Commencer l\'aventure',fn:()=>renderAll()}]);
}

document.getElementById('start-btn').onclick=()=>{if(selectedHeroes.length===numPlayers)startGame();};
renderSetup();
